import{_ as i,o as e,c as o,ag as n}from"./chunks/framework.eQLvDOR_.js";const p=JSON.parse('{"title":"obsidian-as-second-brain","description":"","frontmatter":{"title":"obsidian-as-second-brain","concept":"Obsidian 作为第二大脑","concept_id":"obsidian-as-second-brain","aliases":[],"sources":["02_Library/AI_Prompt_Engineering/[AI_Prompt_Engineering] Prompting is the worst way to use Claude. Do this instead_.md"],"related_concepts":["[[context-optimization]]"],"created_at":"2026-04-18","last_compiled":"2026-04-18"},"headers":[],"relativePath":"wiki/concepts/obsidian-as-second-brain.md","filePath":"wiki/concepts/obsidian-as-second-brain.md","lastUpdated":null}'),t={name:"wiki/concepts/obsidian-as-second-brain.md"};function s(d,a,r,c,l,b){return e(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="obsidian-作为第二大脑-obsidian-as-second-brain" tabindex="-1">Obsidian 作为第二大脑 (Obsidian as Second Brain) <a class="header-anchor" href="#obsidian-作为第二大脑-obsidian-as-second-brain" aria-label="Permalink to &quot;Obsidian 作为第二大脑 (Obsidian as Second Brain)&quot;">​</a></h1><h2 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h2><p>使用 Obsidian (一款本地 Markdown 笔记软件) 来构建和组织 AI 的上下文，借由目录结构、双向链接使得 AI 的工作环境（工作流设定、历史、知识积累）变得持久可见、可编辑。</p><h2 id="核心要点" tabindex="-1">核心要点 <a class="header-anchor" href="#核心要点" aria-label="Permalink to &quot;核心要点&quot;">​</a></h2><ul><li><strong>基于物理存在的提示词</strong>：与其每次开启新会话靠长文 Prompt，不如维护一系列含有工作模式描述的本地 <code>.md</code> 文件。</li><li><strong>与工作区同步</strong>：通过让代码助手直接挂载此类 Obsidian Vault 文件夹，使得每次 Agent 开始任务前主动从这个“第二大脑”拉取人设和最新约束条件。</li></ul><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><p>可以设立一个具体的项目结构如 <code>/Project/Agent_Memory</code> 交由 Obsidian 渲染编辑，包括诸如 <code>Rules.md</code>, <code>Memory.md</code>, <code>Current_Tasks.md</code>。这让你能在日常笔记流中无缝修改 AI 的大脑参数。</p><h2 id="关联概念" tabindex="-1">关联概念 <a class="header-anchor" href="#关联概念" aria-label="Permalink to &quot;关联概念&quot;">​</a></h2><ul><li><a href="/s/webclips/wiki/concepts/context-optimization.html">context-optimization</a> — 属于通过预置环境代替单次超大文本输入的实践。</li></ul>',9)])])}const h=i(t,[["render",s]]);export{p as __pageData,h as default};
